/// GOptionEntry:
/// @long_name: The long name of an option can be used to specify it
/// in a commandline as `--long_name`. Every option must have a
/// long name. To resolve conflicts if multiple option groups contain
/// the same long name, it is also possible to specify the option as
/// `--groupname-long_name`.
/// @short_name: If an option has a short name, it can be specified
/// `-short_name` in a commandline. @short_name must be  a printable
/// ASCII character different from '-', or zero if the option has no
/// short name.
/// @flags: Flags from #GOptionFlags
/// @arg: The type of the option, as a #GOptionArg
/// @arg_data: If the @arg type is %G_OPTION_ARG_CALLBACK, then @arg_data
/// must point to a #GOptionArgFunc callback function, which will be
/// called to handle the extra argument. Otherwise, @arg_data is a
/// pointer to a location to store the value, the required type of
/// the location depends on the @arg type:
/// - %G_OPTION_ARG_NONE: %gboolean
/// - %G_OPTION_ARG_STRING: %gchar*
/// - %G_OPTION_ARG_INT: %gint
/// - %G_OPTION_ARG_FILENAME: %gchar*
/// - %G_OPTION_ARG_STRING_ARRAY: %gchar**
/// - %G_OPTION_ARG_FILENAME_ARRAY: %gchar**
/// - %G_OPTION_ARG_DOUBLE: %gdouble
/// If @arg type is %G_OPTION_ARG_STRING or %G_OPTION_ARG_FILENAME,
/// the location will contain a newly allocated string if the option
/// was given. That string needs to be freed by the callee using g_free().
/// Likewise if @arg type is %G_OPTION_ARG_STRING_ARRAY or
/// %G_OPTION_ARG_FILENAME_ARRAY, the data should be freed using g_strfreev().
/// @description: the description for the option in `--help`
/// output. The @description is translated using the @translate_func
/// of the group, see g_option_group_set_translation_domain().
/// @arg_description: The placeholder to use for the extra argument parsed
/// by the option in `--help` output. The @arg_description is translated
/// using the @translate_func of the group, see
/// g_option_group_set_translation_domain().
///
/// A GOptionEntry struct defines a single option. To have an effect, they
/// must be added to a #GOptionGroup with g_option_context_add_main_entries()
/// or g_option_group_add_entries().
final class _GOptionEntry extends ffi.Struct {
  external ffi.Pointer<gchar> long_name;

  @gchar()
  external int short_name;

  @gint()
  external int flags;

  @ffi.UnsignedInt()
  external int argAsInt;

  GOptionArg get arg => GOptionArg.fromValue(argAsInt);

  external gpointer arg_data;

  external ffi.Pointer<gchar> description;

  external ffi.Pointer<gchar> arg_description;
}

/// GOptionArg:
/// @G_OPTION_ARG_NONE: No extra argument. This is useful for simple flags or booleans.
/// @G_OPTION_ARG_STRING: The option takes a UTF-8 string argument.
/// @G_OPTION_ARG_INT: The option takes an integer argument.
/// @G_OPTION_ARG_CALLBACK: The option provides a callback (of type
/// #GOptionArgFunc) to parse the extra argument.
/// @G_OPTION_ARG_FILENAME: The option takes a filename as argument, which will
/// be in the GLib filename encoding rather than UTF-8.
/// @G_OPTION_ARG_STRING_ARRAY: The option takes a string argument, multiple
/// uses of the option are collected into an array of strings.
/// @G_OPTION_ARG_FILENAME_ARRAY: The option takes a filename as argument,
/// multiple uses of the option are collected into an array of strings.
/// @G_OPTION_ARG_DOUBLE: The option takes a double argument. The argument
/// can be formatted either for the user's locale or for the "C" locale.
/// Since 2.12
/// @G_OPTION_ARG_INT64: The option takes a 64-bit integer. Like
/// %G_OPTION_ARG_INT but for larger numbers. The number can be in
/// decimal base, or in hexadecimal (when prefixed with `0x`, for
/// example, `0xffffffff`). Since 2.12
///
/// The #GOptionArg enum values determine which type of extra argument the
/// options expect to find. If an option expects an extra argument, it can
/// be specified in several ways; with a short option: `-x arg`, with a long
/// option: `--name arg` or combined in a single argument: `--name=arg`.
enum GOptionArg {
  G_OPTION_ARG_NONE(0),
  G_OPTION_ARG_STRING(1),
  G_OPTION_ARG_INT(2),
  G_OPTION_ARG_CALLBACK(3),
  G_OPTION_ARG_FILENAME(4),
  G_OPTION_ARG_STRING_ARRAY(5),
  G_OPTION_ARG_FILENAME_ARRAY(6),
  G_OPTION_ARG_DOUBLE(7),
  G_OPTION_ARG_INT64(8);

  final int value;
  const GOptionArg(this.value);

  static GOptionArg fromValue(int value) => switch (value) {
    0 => G_OPTION_ARG_NONE,
    1 => G_OPTION_ARG_STRING,
    2 => G_OPTION_ARG_INT,
    3 => G_OPTION_ARG_CALLBACK,
    4 => G_OPTION_ARG_FILENAME,
    5 => G_OPTION_ARG_STRING_ARRAY,
    6 => G_OPTION_ARG_FILENAME_ARRAY,
    7 => G_OPTION_ARG_DOUBLE,
    8 => G_OPTION_ARG_INT64,
    _ => throw ArgumentError("Unknown value for GOptionArg: $value"),
  };
}

/// GOptionFlags:
/// @G_OPTION_FLAG_NONE: No flags. Since: 2.42.
/// @G_OPTION_FLAG_HIDDEN: The option doesn't appear in `--help` output.
/// @G_OPTION_FLAG_IN_MAIN: The option appears in the main section of the
/// `--help` output, even if it is defined in a group.
/// @G_OPTION_FLAG_REVERSE: For options of the %G_OPTION_ARG_NONE kind, this
/// flag indicates that the sense of the option is reversed. i.e. %FALSE will
/// be stored into the argument rather than %TRUE.
/// @G_OPTION_FLAG_NO_ARG: For options of the %G_OPTION_ARG_CALLBACK kind,
/// this flag indicates that the callback does not take any argument
/// (like a %G_OPTION_ARG_NONE option). Since 2.8
/// @G_OPTION_FLAG_FILENAME: For options of the %G_OPTION_ARG_CALLBACK
/// kind, this flag indicates that the argument should be passed to the
/// callback in the GLib filename encoding rather than UTF-8. Since 2.8
/// @G_OPTION_FLAG_OPTIONAL_ARG: For options of the %G_OPTION_ARG_CALLBACK
/// kind, this flag indicates that the argument supply is optional.
/// If no argument is given then data of %GOptionParseFunc will be
/// set to NULL. Since 2.8
/// @G_OPTION_FLAG_NOALIAS: This flag turns off the automatic conflict
/// resolution which prefixes long option names with `groupname-` if
/// there is a conflict. This option should only be used in situations
/// where aliasing is necessary to model some legacy commandline interface.
/// It is not safe to use this option, unless all option groups are under
/// your direct control. Since 2.8.
///
/// Flags which modify individual options.
enum GOptionFlags {
  G_OPTION_FLAG_NONE(0),
  G_OPTION_FLAG_HIDDEN(1),
  G_OPTION_FLAG_IN_MAIN(2),
  G_OPTION_FLAG_REVERSE(4),
  G_OPTION_FLAG_NO_ARG(8),
  G_OPTION_FLAG_FILENAME(16),
  G_OPTION_FLAG_OPTIONAL_ARG(32),
  G_OPTION_FLAG_NOALIAS(64);

  final int value;
  const GOptionFlags(this.value);

  static GOptionFlags fromValue(int value) => switch (value) {
    0 => G_OPTION_FLAG_NONE,
    1 => G_OPTION_FLAG_HIDDEN,
    2 => G_OPTION_FLAG_IN_MAIN,
    4 => G_OPTION_FLAG_REVERSE,
    8 => G_OPTION_FLAG_NO_ARG,
    16 => G_OPTION_FLAG_FILENAME,
    32 => G_OPTION_FLAG_OPTIONAL_ARG,
    64 => G_OPTION_FLAG_NOALIAS,
    _ => throw ArgumentError("Unknown value for GOptionFlags: $value"),
  };
}

/// GOptionError:
/// @G_OPTION_ERROR_UNKNOWN_OPTION: An option was not known to the parser.
/// This error will only be reported, if the parser hasn't been instructed
/// to ignore unknown options, see g_option_context_set_ignore_unknown_options().
/// @G_OPTION_ERROR_BAD_VALUE: A value couldn't be parsed.
/// @G_OPTION_ERROR_FAILED: A #GOptionArgFunc callback failed.
