/// function returns. E.g. for our above string type:
///
/// |[<!-- language="C" -->
/// // only free strings without a specific flag for static storage
/// if (!(value->data[1].v_uint & G_VALUE_NOCOPY_CONTENTS))
/// g_free (value->data[0].v_pointer);
/// ]|
///
/// Since: 2.78
typedef GTypeValueFreeFunc =
    ffi.Pointer<ffi.NativeFunction<GTypeValueFreeFuncFunction>>;
typedef GTypeValueFreeFuncFunction =
    ffi.Void Function(ffi.Pointer<GValue> value);
typedef DartGTypeValueFreeFuncFunction =
    void Function(ffi.Pointer<GValue> value);

