    1 => G_SIGNAL_RUN_FIRST,
    2 => G_SIGNAL_RUN_LAST,
    4 => G_SIGNAL_RUN_CLEANUP,
    8 => G_SIGNAL_NO_RECURSE,
    16 => G_SIGNAL_DETAILED,
    32 => G_SIGNAL_ACTION,
    64 => G_SIGNAL_NO_HOOKS,
    128 => G_SIGNAL_MUST_COLLECT,
