  final int value;
  const GFileMonitorFlags(this.value);

  static GFileMonitorFlags fromValue(int value) => switch (value) {
    0 => G_FILE_MONITOR_NONE,
    1 => G_FILE_MONITOR_WATCH_MOUNTS,
    2 => G_FILE_MONITOR_SEND_MOVED,
    4 => G_FILE_MONITOR_WATCH_HARD_LINKS,
