    _ => throw ArgumentError("Unknown value for GFileMonitorFlags: $value"),
  };
}

/// GFileType:
/// @G_FILE_TYPE_UNKNOWN: File's type is unknown.
/// @G_FILE_TYPE_REGULAR: File handle represents a regular file.
/// @G_FILE_TYPE_DIRECTORY: File handle represents a directory.
/// @G_FILE_TYPE_SYMBOLIC_LINK: File handle represents a symbolic link
/// (Unix systems).
/// @G_FILE_TYPE_SPECIAL: File is a "special" file, such as a socket, fifo,
/// block device, or character device.
/// @G_FILE_TYPE_SHORTCUT: File is a shortcut (Windows systems).
/// @G_FILE_TYPE_MOUNTABLE: File is a mountable location.
///
/// Indicates the file's on-disk type.
///
/// On Windows systems a file will never have %G_FILE_TYPE_SYMBOLIC_LINK type;
/// use #GFileInfo and %G_FILE_ATTRIBUTE_STANDARD_IS_SYMLINK to determine
/// whether a file is a symlink or not. This is due to the fact that NTFS does
/// not have a single filesystem object type for symbolic links - it has
/// files that symlink to files, and directories that symlink to directories.
/// #GFileType enumeration cannot precisely represent this important distinction,
/// which is why all Windows symlinks will continue to be reported as
/// %G_FILE_TYPE_REGULAR or %G_FILE_TYPE_DIRECTORY.
enum GFileType {
  G_FILE_TYPE_UNKNOWN(0),
  G_FILE_TYPE_REGULAR(1),
  G_FILE_TYPE_DIRECTORY(2),
  G_FILE_TYPE_SYMBOLIC_LINK(3),
  G_FILE_TYPE_SPECIAL(4),
  G_FILE_TYPE_SHORTCUT(5),
  G_FILE_TYPE_MOUNTABLE(6);

  final int value;
  const GFileType(this.value);

  static GFileType fromValue(int value) => switch (value) {
    0 => G_FILE_TYPE_UNKNOWN,
    1 => G_FILE_TYPE_REGULAR,
    2 => G_FILE_TYPE_DIRECTORY,
    3 => G_FILE_TYPE_SYMBOLIC_LINK,
    4 => G_FILE_TYPE_SPECIAL,
    5 => G_FILE_TYPE_SHORTCUT,
    6 => G_FILE_TYPE_MOUNTABLE,
    _ => throw ArgumentError("Unknown value for GFileType: $value"),
  };
}

