  G_FILE_MONITOR_EVENT_UNMOUNTED(6),
  G_FILE_MONITOR_EVENT_MOVED(7),
  G_FILE_MONITOR_EVENT_RENAMED(8),
  G_FILE_MONITOR_EVENT_MOVED_IN(9),
