/// GUnixSocketAddressType:
/// @G_UNIX_SOCKET_ADDRESS_INVALID: invalid
/// @G_UNIX_SOCKET_ADDRESS_ANONYMOUS: anonymous
/// @G_UNIX_SOCKET_ADDRESS_PATH: a filesystem path
/// @G_UNIX_SOCKET_ADDRESS_ABSTRACT: an abstract name
/// @G_UNIX_SOCKET_ADDRESS_ABSTRACT_PADDED: an abstract name, 0-padded
/// to the full length of a unix socket name
///
/// The type of name used by a #GUnixSocketAddress.
/// %G_UNIX_SOCKET_ADDRESS_PATH indicates a traditional unix domain
/// socket bound to a filesystem path. %G_UNIX_SOCKET_ADDRESS_ANONYMOUS
/// indicates a socket not bound to any name (eg, a client-side socket,
/// or a socket created with socketpair()).
///
/// For abstract sockets, there are two incompatible ways of naming
/// them; the man pages suggest using the entire `struct sockaddr_un`
/// as the name, padding the unused parts of the %sun_path field with
/// zeroes; this corresponds to %G_UNIX_SOCKET_ADDRESS_ABSTRACT_PADDED.
/// However, many programs instead just use a portion of %sun_path, and
/// pass an appropriate smaller length to bind() or connect(). This is
/// %G_UNIX_SOCKET_ADDRESS_ABSTRACT.
///
/// Since: 2.26
enum GUnixSocketAddressType {
  G_UNIX_SOCKET_ADDRESS_INVALID(0),
  G_UNIX_SOCKET_ADDRESS_ANONYMOUS(1),
  G_UNIX_SOCKET_ADDRESS_PATH(2),
  G_UNIX_SOCKET_ADDRESS_ABSTRACT(3),
  G_UNIX_SOCKET_ADDRESS_ABSTRACT_PADDED(4);

  final int value;
  const GUnixSocketAddressType(this.value);

  static GUnixSocketAddressType fromValue(int value) => switch (value) {
    0 => G_UNIX_SOCKET_ADDRESS_INVALID,
    1 => G_UNIX_SOCKET_ADDRESS_ANONYMOUS,
    2 => G_UNIX_SOCKET_ADDRESS_PATH,
    3 => G_UNIX_SOCKET_ADDRESS_ABSTRACT,
    4 => G_UNIX_SOCKET_ADDRESS_ABSTRACT_PADDED,
    _ => throw ArgumentError(
      "Unknown value for GUnixSocketAddressType: $value",
    ),
  };
}

