/// GDBusProxyFlags:
/// @G_DBUS_PROXY_FLAGS_NONE: No flags set.
/// @G_DBUS_PROXY_FLAGS_DO_NOT_LOAD_PROPERTIES: Don't load properties.
/// @G_DBUS_PROXY_FLAGS_DO_NOT_CONNECT_SIGNALS: Don't connect to signals on the remote object.
/// @G_DBUS_PROXY_FLAGS_DO_NOT_AUTO_START: If the proxy is for a well-known name,
/// do not ask the bus to launch an owner during proxy initialization or a method call.
/// This flag is only meaningful in proxies for well-known names.
/// @G_DBUS_PROXY_FLAGS_GET_INVALIDATED_PROPERTIES: If set, the property value for any __invalidated property__ will be (asynchronously) retrieved upon receiving the [`PropertiesChanged`](http://dbus.freedesktop.org/doc/dbus-specification.html#standard-interfaces-properties) D-Bus signal and the property will not cause emission of the #GDBusProxy::g-properties-changed signal. When the value is received the #GDBusProxy::g-properties-changed signal is emitted for the property along with the retrieved value. Since 2.32.
/// @G_DBUS_PROXY_FLAGS_DO_NOT_AUTO_START_AT_CONSTRUCTION: If the proxy is for a well-known name,
/// do not ask the bus to launch an owner during proxy initialization, but allow it to be
/// autostarted by a method call. This flag is only meaningful in proxies for well-known names,
/// and only if %G_DBUS_PROXY_FLAGS_DO_NOT_AUTO_START is not also specified.
/// @G_DBUS_PROXY_FLAGS_NO_MATCH_RULE: Don't actually send the AddMatch D-Bus
/// call for this signal subscription. This gives you more control
/// over which match rules you add (but you must add them manually). (Since: 2.72)
///
/// Flags used when constructing an instance of a #GDBusProxy derived class.
///
/// Since: 2.26
enum GDBusProxyFlags {
  G_DBUS_PROXY_FLAGS_NONE(0),
  G_DBUS_PROXY_FLAGS_DO_NOT_LOAD_PROPERTIES(1),
  G_DBUS_PROXY_FLAGS_DO_NOT_CONNECT_SIGNALS(2),
  G_DBUS_PROXY_FLAGS_DO_NOT_AUTO_START(4),
  G_DBUS_PROXY_FLAGS_GET_INVALIDATED_PROPERTIES(8),
  G_DBUS_PROXY_FLAGS_DO_NOT_AUTO_START_AT_CONSTRUCTION(16),
  G_DBUS_PROXY_FLAGS_NO_MATCH_RULE(32);

  final int value;
  const GDBusProxyFlags(this.value);

  static GDBusProxyFlags fromValue(int value) => switch (value) {
    0 => G_DBUS_PROXY_FLAGS_NONE,
    1 => G_DBUS_PROXY_FLAGS_DO_NOT_LOAD_PROPERTIES,
    2 => G_DBUS_PROXY_FLAGS_DO_NOT_CONNECT_SIGNALS,
    4 => G_DBUS_PROXY_FLAGS_DO_NOT_AUTO_START,
    8 => G_DBUS_PROXY_FLAGS_GET_INVALIDATED_PROPERTIES,
    16 => G_DBUS_PROXY_FLAGS_DO_NOT_AUTO_START_AT_CONSTRUCTION,
    32 => G_DBUS_PROXY_FLAGS_NO_MATCH_RULE,
    _ => throw ArgumentError("Unknown value for GDBusProxyFlags: $value"),
  };
}

/// GDBusError:
/// @G_DBUS_ERROR_FAILED:
/// A generic error; "something went wrong" - see the error message for
/// more.
/// @G_DBUS_ERROR_NO_MEMORY:
/// There was not enough memory to complete an operation.
/// @G_DBUS_ERROR_SERVICE_UNKNOWN:
/// The bus doesn't know how to launch a service to supply the bus name
/// you wanted.
/// @G_DBUS_ERROR_NAME_HAS_NO_OWNER:
/// The bus name you referenced doesn't exist (i.e. no application owns
/// it).
/// @G_DBUS_ERROR_NO_REPLY:
/// No reply to a message expecting one, usually means a timeout occurred.
/// @G_DBUS_ERROR_IO_ERROR:
/// Something went wrong reading or writing to a socket, for example.
/// @G_DBUS_ERROR_BAD_ADDRESS:
/// A D-Bus bus address was malformed.
/// @G_DBUS_ERROR_NOT_SUPPORTED:
/// Requested operation isn't supported (like ENOSYS on UNIX).
/// @G_DBUS_ERROR_LIMITS_EXCEEDED:
/// Some limited resource is exhausted.
/// @G_DBUS_ERROR_ACCESS_DENIED:
/// Security restrictions don't allow doing what you're trying to do.
/// @G_DBUS_ERROR_AUTH_FAILED:
/// Authentication didn't work.
/// @G_DBUS_ERROR_NO_SERVER:
/// Unable to connect to server (probably caused by ECONNREFUSED on a
/// socket).
/// @G_DBUS_ERROR_TIMEOUT:
/// Certain timeout errors, possibly ETIMEDOUT on a socket.  Note that
/// %G_DBUS_ERROR_NO_REPLY is used for message reply timeouts. Warning:
/// this is confusingly-named given that %G_DBUS_ERROR_TIMED_OUT also
/// exists. We can't fix it for compatibility reasons so just be
/// careful.
/// @G_DBUS_ERROR_NO_NETWORK:
/// No network access (probably ENETUNREACH on a socket).
/// @G_DBUS_ERROR_ADDRESS_IN_USE:
/// Can't bind a socket since its address is in use (i.e. EADDRINUSE).
/// @G_DBUS_ERROR_DISCONNECTED:
/// The connection is disconnected and you're trying to use it.
/// @G_DBUS_ERROR_INVALID_ARGS:
/// Invalid arguments passed to a method call.
/// @G_DBUS_ERROR_FILE_NOT_FOUND:
/// Missing file.
/// @G_DBUS_ERROR_FILE_EXISTS:
/// Existing file and the operation you're using does not silently overwrite.
/// @G_DBUS_ERROR_UNKNOWN_METHOD:
/// Method name you invoked isn't known by the object you invoked it on.
/// @G_DBUS_ERROR_UNKNOWN_OBJECT:
/// Object you invoked a method on isn't known. Since 2.42
/// @G_DBUS_ERROR_UNKNOWN_INTERFACE:
/// Interface you invoked a method on isn't known by the object. Since 2.42
/// @G_DBUS_ERROR_UNKNOWN_PROPERTY:
/// Property you tried to access isn't known by the object. Since 2.42
/// @G_DBUS_ERROR_PROPERTY_READ_ONLY:
/// Property you tried to set is read-only. Since 2.42
/// @G_DBUS_ERROR_TIMED_OUT:
/// Certain timeout errors, e.g. while starting a service. Warning: this is
/// confusingly-named given that %G_DBUS_ERROR_TIMEOUT also exists. We
/// can't fix it for compatibility reasons so just be careful.
/// @G_DBUS_ERROR_MATCH_RULE_NOT_FOUND:
/// Tried to remove or modify a match rule that didn't exist.
/// @G_DBUS_ERROR_MATCH_RULE_INVALID:
/// The match rule isn't syntactically valid.
/// @G_DBUS_ERROR_SPAWN_EXEC_FAILED:
/// While starting a new process, the exec() call failed.
/// @G_DBUS_ERROR_SPAWN_FORK_FAILED:
/// While starting a new process, the fork() call failed.
/// @G_DBUS_ERROR_SPAWN_CHILD_EXITED:
/// While starting a new process, the child exited with a status code.
/// @G_DBUS_ERROR_SPAWN_CHILD_SIGNALED:
/// While starting a new process, the child exited on a signal.
/// @G_DBUS_ERROR_SPAWN_FAILED:
/// While starting a new process, something went wrong.
/// @G_DBUS_ERROR_SPAWN_SETUP_FAILED:
/// We failed to setup the environment correctly.
/// @G_DBUS_ERROR_SPAWN_CONFIG_INVALID:
/// We failed to setup the config parser correctly.
/// @G_DBUS_ERROR_SPAWN_SERVICE_INVALID:
/// Bus name was not valid.
/// @G_DBUS_ERROR_SPAWN_SERVICE_NOT_FOUND:
/// Service file not found in system-services directory.
/// @G_DBUS_ERROR_SPAWN_PERMISSIONS_INVALID:
/// Permissions are incorrect on the setuid helper.
/// @G_DBUS_ERROR_SPAWN_FILE_INVALID:
/// Service file invalid (Name, User or Exec missing).
/// @G_DBUS_ERROR_SPAWN_NO_MEMORY:
/// Tried to get a UNIX process ID and it wasn't available.
/// @G_DBUS_ERROR_UNIX_PROCESS_ID_UNKNOWN:
/// Tried to get a UNIX process ID and it wasn't available.
/// @G_DBUS_ERROR_INVALID_SIGNATURE:
/// A type signature is not valid.
/// @G_DBUS_ERROR_INVALID_FILE_CONTENT:
/// A file contains invalid syntax or is otherwise broken.
/// @G_DBUS_ERROR_SELINUX_SECURITY_CONTEXT_UNKNOWN:
/// Asked for SELinux security context and it wasn't available.
/// @G_DBUS_ERROR_ADT_AUDIT_DATA_UNKNOWN:
/// Asked for ADT audit data and it wasn't available.
/// @G_DBUS_ERROR_OBJECT_PATH_IN_USE:
/// There's already an object with the requested object path.
///
/// Error codes for the %G_DBUS_ERROR error domain.
///
/// Since: 2.26
enum GDBusError {
