  G_DBUS_ERROR_SPAWN_NO_MEMORY(34),
  G_DBUS_ERROR_UNIX_PROCESS_ID_UNKNOWN(35),
  G_DBUS_ERROR_INVALID_SIGNATURE(36),
  G_DBUS_ERROR_INVALID_FILE_CONTENT(37),
  G_DBUS_ERROR_SELINUX_SECURITY_CONTEXT_UNKNOWN(38),
