/// GDBusConnectionFlags:
/// @G_DBUS_CONNECTION_FLAGS_NONE: No flags set.
/// @G_DBUS_CONNECTION_FLAGS_AUTHENTICATION_CLIENT: Perform authentication against server.
/// @G_DBUS_CONNECTION_FLAGS_AUTHENTICATION_SERVER: Perform authentication against client.
/// @G_DBUS_CONNECTION_FLAGS_AUTHENTICATION_ALLOW_ANONYMOUS: When
/// authenticating as a server, allow the anonymous authentication
/// method.
/// @G_DBUS_CONNECTION_FLAGS_MESSAGE_BUS_CONNECTION: Pass this flag if connecting to a peer that is a
/// message bus. This means that the Hello() method will be invoked as part of the connection setup.
/// @G_DBUS_CONNECTION_FLAGS_DELAY_MESSAGE_PROCESSING: If set, processing of D-Bus messages is
/// delayed until g_dbus_connection_start_message_processing() is called.
/// @G_DBUS_CONNECTION_FLAGS_AUTHENTICATION_REQUIRE_SAME_USER: When authenticating
/// as a server, require the UID of the peer to be the same as the UID of the server. (Since: 2.68)
/// @G_DBUS_CONNECTION_FLAGS_CROSS_NAMESPACE: When authenticating, try to use
/// protocols that work across a Linux user namespace boundary, even if this
/// reduces interoperability with older D-Bus implementations. This currently
/// affects client-side `EXTERNAL` authentication, for which this flag makes
/// connections to a server in another user namespace succeed, but causes
/// a deadlock when connecting to a GDBus server older than 2.73.3. Since: 2.74
///
/// Flags used when creating a new #GDBusConnection.
///
/// Since: 2.26
enum GDBusConnectionFlags {
  G_DBUS_CONNECTION_FLAGS_NONE(0),
  G_DBUS_CONNECTION_FLAGS_AUTHENTICATION_CLIENT(1),
  G_DBUS_CONNECTION_FLAGS_AUTHENTICATION_SERVER(2),
  G_DBUS_CONNECTION_FLAGS_AUTHENTICATION_ALLOW_ANONYMOUS(4),
  G_DBUS_CONNECTION_FLAGS_MESSAGE_BUS_CONNECTION(8),
  G_DBUS_CONNECTION_FLAGS_DELAY_MESSAGE_PROCESSING(16),
  G_DBUS_CONNECTION_FLAGS_AUTHENTICATION_REQUIRE_SAME_USER(32),
  G_DBUS_CONNECTION_FLAGS_CROSS_NAMESPACE(64);

  final int value;
  const GDBusConnectionFlags(this.value);

  static GDBusConnectionFlags fromValue(int value) => switch (value) {
    0 => G_DBUS_CONNECTION_FLAGS_NONE,
    1 => G_DBUS_CONNECTION_FLAGS_AUTHENTICATION_CLIENT,
    2 => G_DBUS_CONNECTION_FLAGS_AUTHENTICATION_SERVER,
    4 => G_DBUS_CONNECTION_FLAGS_AUTHENTICATION_ALLOW_ANONYMOUS,
    8 => G_DBUS_CONNECTION_FLAGS_MESSAGE_BUS_CONNECTION,
    16 => G_DBUS_CONNECTION_FLAGS_DELAY_MESSAGE_PROCESSING,
    32 => G_DBUS_CONNECTION_FLAGS_AUTHENTICATION_REQUIRE_SAME_USER,
    64 => G_DBUS_CONNECTION_FLAGS_CROSS_NAMESPACE,
    _ => throw ArgumentError("Unknown value for GDBusConnectionFlags: $value"),
  };
}

