  static const NM_CLIENT_PERMISSION_LAST = NM_CLIENT_PERMISSION_WIFI_SCAN;

  final int value;
  const NMClientPermission(this.value);

  static NMClientPermission fromValue(int value) => switch (value) {
    0 => NM_CLIENT_PERMISSION_NONE,
    1 => NM_CLIENT_PERMISSION_ENABLE_DISABLE_NETWORK,
    2 => NM_CLIENT_PERMISSION_ENABLE_DISABLE_WIFI,
    3 => NM_CLIENT_PERMISSION_ENABLE_DISABLE_WWAN,
    4 => NM_CLIENT_PERMISSION_ENABLE_DISABLE_WIMAX,
    5 => NM_CLIENT_PERMISSION_SLEEP_WAKE,
    6 => NM_CLIENT_PERMISSION_NETWORK_CONTROL,
    7 => NM_CLIENT_PERMISSION_WIFI_SHARE_PROTECTED,
    8 => NM_CLIENT_PERMISSION_WIFI_SHARE_OPEN,
    9 => NM_CLIENT_PERMISSION_SETTINGS_MODIFY_SYSTEM,
    10 => NM_CLIENT_PERMISSION_SETTINGS_MODIFY_OWN,
    11 => NM_CLIENT_PERMISSION_SETTINGS_MODIFY_HOSTNAME,
    12 => NM_CLIENT_PERMISSION_SETTINGS_MODIFY_GLOBAL_DNS,
