    0 => NM_SETTING_MAC_RANDOMIZATION_DEFAULT,
    1 => NM_SETTING_MAC_RANDOMIZATION_NEVER,
    2 => NM_SETTING_MAC_RANDOMIZATION_ALWAYS,
    _ => throw ArgumentError(
      "Unknown value for NMSettingMacRandomization: $value",
    ),
  };
}

