/// NMConnectionInterface:
/// @parent: the parent interface struct
/// @secrets_updated: emitted when the connection's secrets are updated
/// @secrets_cleared: emitted when the connection's secrets are cleared
/// @changed: emitted when any change to the connection's settings occurs
final class NMConnectionInterface extends ffi.Struct {
  external GTypeInterface parent;

  external ffi.Pointer<
    ffi.NativeFunction<
      ffi.Void Function(
        ffi.Pointer<NMConnection> connection,
        ffi.Pointer<ffi.Char> setting,
      )
    >
  >
  secrets_updated;

  external ffi.Pointer<
    ffi.NativeFunction<ffi.Void Function(ffi.Pointer<NMConnection> connection)>
  >
  secrets_cleared;

  external ffi.Pointer<
    ffi.NativeFunction<ffi.Void Function(ffi.Pointer<NMConnection> connection)>
  >
  changed;
}

typedef NMConnection = _NMConnection;

/// NMConnectionSerializationFlags:
/// @NM_CONNECTION_SERIALIZE_ALL: serialize all properties (including secrets)
/// @NM_CONNECTION_SERIALIZE_WITH_NON_SECRET: serialize properties that are
/// not secrets. Since 1.32.
/// @NM_CONNECTION_SERIALIZE_NO_SECRETS: this is a deprecated alias for
/// @NM_CONNECTION_SERIALIZE_WITH_NON_SECRET.
/// @NM_CONNECTION_SERIALIZE_WITH_SECRETS: serialize all secrets. This flag is
/// ignored if any of @NM_CONNECTION_SERIALIZE_WITH_SECRETS_AGENT_OWNED,
/// @NM_CONNECTION_SERIALIZE_WITH_SECRETS_SYSTEM_OWNED or
/// @NM_CONNECTION_SERIALIZE_WITH_SECRETS_NOT_SAVED is set. Since 1.32.
/// @NM_CONNECTION_SERIALIZE_ONLY_SECRETS: a deprecated alias for
/// @NM_CONNECTION_SERIALIZE_WITH_SECRETS.
/// @NM_CONNECTION_SERIALIZE_WITH_SECRETS_AGENT_OWNED: serialize agent-owned
/// secrets. Since: 1.20.
/// @NM_CONNECTION_SERIALIZE_WITH_SECRETS_SYSTEM_OWNED: serialize system-owned
/// secrets. Since: 1.32.
/// @NM_CONNECTION_SERIALIZE_WITH_SECRETS_NOT_SAVED: serialize secrets that
/// are marked as never saved. Since: 1.32.
///
/// These flags determine which properties are serialized when calling
/// nm_connection_to_dbus().
enum NMConnectionSerializationFlags {
  NM_CONNECTION_SERIALIZE_ALL(0),
  NM_CONNECTION_SERIALIZE_WITH_NON_SECRET(1),
  NM_CONNECTION_SERIALIZE_WITH_SECRETS(2),
  NM_CONNECTION_SERIALIZE_WITH_SECRETS_AGENT_OWNED(4),
  NM_CONNECTION_SERIALIZE_WITH_SECRETS_SYSTEM_OWNED(8),
  NM_CONNECTION_SERIALIZE_WITH_SECRETS_NOT_SAVED(16);

  static const NM_CONNECTION_SERIALIZE_NO_SECRETS =
      NM_CONNECTION_SERIALIZE_WITH_NON_SECRET;
  static const NM_CONNECTION_SERIALIZE_ONLY_SECRETS =
      NM_CONNECTION_SERIALIZE_WITH_SECRETS;

  final int value;
  const NMConnectionSerializationFlags(this.value);

  static NMConnectionSerializationFlags fromValue(int value) => switch (value) {
    0 => NM_CONNECTION_SERIALIZE_ALL,
    1 => NM_CONNECTION_SERIALIZE_WITH_NON_SECRET,
    2 => NM_CONNECTION_SERIALIZE_WITH_SECRETS,
    4 => NM_CONNECTION_SERIALIZE_WITH_SECRETS_AGENT_OWNED,
    8 => NM_CONNECTION_SERIALIZE_WITH_SECRETS_SYSTEM_OWNED,
    16 => NM_CONNECTION_SERIALIZE_WITH_SECRETS_NOT_SAVED,
    _ => throw ArgumentError(
      "Unknown value for NMConnectionSerializationFlags: $value",
    ),
  };

  @override
  String toString() {
    if (this == NM_CONNECTION_SERIALIZE_WITH_NON_SECRET)
      return "NMConnectionSerializationFlags.NM_CONNECTION_SERIALIZE_WITH_NON_SECRET, NMConnectionSerializationFlags.NM_CONNECTION_SERIALIZE_NO_SECRETS";
    if (this == NM_CONNECTION_SERIALIZE_WITH_SECRETS)
      return "NMConnectionSerializationFlags.NM_CONNECTION_SERIALIZE_WITH_SECRETS, NMConnectionSerializationFlags.NM_CONNECTION_SERIALIZE_ONLY_SECRETS";
    return super.toString();
  }
}

